func:
// Envia uma mensagem por tag para o nó eth-ip
var tags_bool = ["iSV_GLP_Closed", "iSV_GLP_Opened", "iZS_Queimador_Piloto", "iZS_Queimador_Principal", "iZS_Emerg", "iZS_Soprador", "iSV_01_Closed", "iSV_01_Opened", "iSV_02_Closed", "iSV_02_Opened", "iCx_Vento_Closed", "iCx_Vento_Opened", "iPiloto_Pronto", "iDefeito_Bool", "iReserva_Bool", "iFimDeCurso_Posicao", "oAciona_Ignicao", "oAciona_Soprador", "oPiloto_Acesso", "oGLP_Piloto_Abrir", "oGLP_Principal_Abrir", "oGLP_Fechada", "oSV_01_Abrir", "oSV_01_Fechar", "oSV_02_Abrir", "oSV_02_Fechar", "oCx_Vento_Out", "oReset_Rele", "Inicio_HMI", "Reset_IHM", "Teste_IHM", "Inicia_Queima", "Final_Queima", "Descendo", "Subindo", "Hab_Descendo", "EMERGENCIA_ALARME1", "Reset_Seq", "trava_supervi", "Teste_Iniciado", "SV_01_DuasSaidas", "SV_02_DuasSaidas", "Selo_TempoSinterizacao", "AUX_A_SV_02", "AUX_F_SV_02", "teste"];
var tags_real = ["iTIT_01_Refratario_PV", "iTIT_02_Ignicao_PV", "iTIT_03_Cx_Vento_PV", "iFIT_01_GLP_PV", "iFIT_01_GLP_Val", "iFIT_02_Ar_PV", "iPIT_01_GLP_PV", "iPIT_02_Gases_PV", "oReserva_Real", "iReserva_Real", "Temp_CxVento_Max", "Min_TempoResfriamento", "Min_TempoSinterizacao", "Parcial_TempoSinterizacao"];
var msgs = [];
tags_bool.forEach(function(t){ msgs.push({topic: t, tag: t, datatype:'BOOL'}); });
tags_real.forEach(function(t){ msgs.push({topic: t, tag: t, datatype:'REAL'}); });
return [msgs];

var plc = flow.get('plc_tags') || {};
// Cada msg chega com msg.topic = nome da tag, msg.payload = valor
if (msg.topic && msg.payload !== undefined) {
    plc[msg.topic] = msg.payload;
}
flow.set('plc_tags', plc);
// Dispara update do dashboard a cada ciclo completo
var total = 60;
var count = (flow.get('read_count') || 0) + 1;
flow.set('read_count', count);
if (count % total === 0) {
    return {payload: plc, topic: 'full_update'};
}
return null;

var plc = msg.payload || {};
var state = flow.get('seq_state') || {
    estado: 'IDLE', step: 0, timer: 0,
    log: [], prev_estado: ''
};

function log(txt) {
    var t = new Date().toLocaleTimeString('pt-BR');
    state.log.unshift('['+t+'] '+txt);
    if(state.log.length > 30) state.log.pop();
}

var writes = {}; // tags a escrever de volta no CLP

// ── Emergência sempre monitorada ────────────────────────────────────────────
if (plc.iZS_Emerg === true && state.estado !== 'FALHA' && state.estado !== 'IDLE') {
    log('!! EMERGÊNCIA: iZS_Emerg ativado - fechando tudo');
    writes.oSV_01_Abrir = false; writes.oSV_01_Fechar = true;
    writes.oSV_02_Abrir = false; writes.oSV_02_Fechar = true;
    writes.oGLP_Piloto_Abrir = false; writes.oGLP_Principal_Abrir = false;
    writes.oAciona_Ignicao = false;
    writes.EMERGENCIA_ALARME1 = true;
    state.estado = 'FALHA'; state.step = 0; state.timer = 0;
}

// ── Máquina de estados ───────────────────────────────────────────────────────
switch(state.estado) {

  case 'IDLE':
    if (plc.Inicio_HMI === true || plc.Inicia_Queima === true) {
        if (plc.iDefeito_Bool === true) {
            log('BLOQUEIO: Defeito ativo - corrija antes de iniciar');
            writes.EMERGENCIA_ALARME1 = true;
            break;
        }
        state.estado = 'PRE_PURGA'; state.step = 0; state.timer = 0;
        log('INÍCIO: Sequência de queima piloto iniciada');
    }
    break;

  case 'PRE_PURGA':
    if (state.step === 0) {
        writes.oAciona_Soprador = true;
        writes.oCx_Vento_Out = true;
        writes.oSV_01_Fechar = true; writes.oSV_01_Abrir = false;
        writes.oSV_02_Fechar = true; writes.oSV_02_Abrir = false;
        log('PURGA: Soprador ligado, aguardando caixa de vento...');
        state.step = 1; state.timer = 0;
    }
    else if (state.step === 1) {
        state.timer++;
        // Aguarda feedback real da caixa de vento (ou timeout 10s)
        if (plc.iCx_Vento_Opened === true || state.timer >= 10) {
            if (!plc.iCx_Vento_Opened) log('AVISO: Timeout caixa de vento - continuando purga');
            else log('PURGA: Caixa de vento ABERTA confirmada');
            state.step = 2; state.timer = 0;
        }
    }
    else if (state.step === 2) {
        state.timer++;
        if (state.timer % 5 === 0) log('PURGA: ' + state.timer + 's / 30s');
        if (state.timer >= 30) {
            state.estado = 'ABRE_SV_GLP'; state.step = 0; state.timer = 0;
            log('PURGA: Concluída (30s)');
        }
    }
    break;

  case 'ABRE_SV_GLP':
    if (state.step === 0) {
        writes.oGLP_Fechada = false;
        log('GLP: Abrindo válvula geral GLP...');
        state.step = 1; state.timer = 0;
    }
    else if (state.step === 1) {
        state.timer++;
        if (plc.iSV_GLP_Opened === true || state.timer >= 8) {
            if (!plc.iSV_GLP_Opened) log('AVISO: Timeout iSV_GLP_Opened');
            else log('GLP: Válvula geral ABERTA - PIT-01: ' + (plc.iPIT_01_GLP_PV||0).toFixed(2) + ' bar');
            state.estado = 'ABRE_SV_PILOTO'; state.step = 0; state.timer = 0;
        }
    }
    break;

  case 'ABRE_SV_PILOTO':
    if (state.step === 0) {
        writes.oSV_01_Abrir = true; writes.oSV_01_Fechar = false;
        writes.oGLP_Piloto_Abrir = true;
        log('SV-01: Abrindo válvula piloto GLP...');
        state.step = 1; state.timer = 0;
    }
    else if (state.step === 1) {
        state.timer++;
        if (plc.iSV_01_Opened === true || state.timer >= 8) {
            if (!plc.iSV_01_Opened) log('AVISO: Timeout iSV_01_Opened');
            else log('SV-01: ABERTA - FIT-01: ' + (plc.iFIT_01_GLP_PV||0).toFixed(1) + ' Nm³/h');
            state.estado = 'IGNICAO'; state.step = 0; state.timer = 0;
        }
    }
    break;

  case 'IGNICAO':
    if (state.step === 0) {
        writes.oAciona_Ignicao = true;
        writes.oPiloto_Acesso = true;
        log('IGNIÇÃO: Transformador ativado - aguardando chama...');
        state.step = 1; state.timer = 0;
    }
    else if (state.step === 1) {
        state.timer++;
        if (plc.iZS_Queimador_Piloto === true) {
            writes.oAciona_Ignicao = false;
            log('IGNIÇÃO: ✓ CHAMA PILOTO CONFIRMADA (iZS_Queimador_Piloto=TRUE) - TIT-02: ' + (plc.iTIT_02_Ignicao_PV||0).toFixed(0) + '°C');
            state.estado = 'PILOTO_ESTAVEL'; state.step = 0; state.timer = 0;
        } else if (state.timer >= 10) {
            // Falha de ignição
            writes.oAciona_Ignicao = false;
            writes.oSV_01_Abrir = false; writes.oSV_01_Fechar = true;
            writes.oGLP_Piloto_Abrir = false;
            writes.EMERGENCIA_ALARME1 = true;
            log('FALHA IGNIÇÃO: iZS_Queimador_Piloto não confirmado em 10s - EMERGÊNCIA');
            state.estado = 'FALHA'; state.step = 0; state.timer = 0;
        } else if (state.timer % 2 === 0) {
            log('IGNIÇÃO: Tentando... ' + state.timer + 's/10s | TIT-02: ' + (plc.iTIT_02_Ignicao_PV||0).toFixed(0) + '°C');
        }
    }
    break;

  case 'PILOTO_ESTAVEL':
    state.timer++;
    if (state.timer % 5 === 0) {
        log('PILOTO OK: TIT-01=' + (plc.iTIT_01_Refratario_PV||0).toFixed(0) + '°C | TIT-02=' + (plc.iTIT_02_Ignicao_PV||0).toFixed(0) + '°C');
    }
    // Verifica se piloto apagou
    if (plc.iZS_Queimador_Piloto === false && state.timer > 3) {
        log('FALHA: Chama piloto perdida!');
        writes.oGLP_Piloto_Abrir = false;
        writes.oSV_01_Abrir = false; writes.oSV_01_Fechar = true;
        writes.EMERGENCIA_ALARME1 = true;
        state.estado = 'FALHA'; state.step = 0; state.timer = 0;
        break;
    }
    // Abre principal quando refratário >= 300°C ou comando forçado
    if ((plc.iTIT_01_Refratario_PV >= 300) || plc.Teste_IHM === true) {
        log('PILOTO: Refratário pronto (' + (plc.iTIT_01_Refratario_PV||0).toFixed(0) + '°C) - abrindo principal');
        state.estado = 'ABRE_PRINCIPAL'; state.step = 0; state.timer = 0;
    }
    break;

  case 'ABRE_PRINCIPAL':
    if (state.step === 0) {
        writes.oSV_02_Abrir = true; writes.oSV_02_Fechar = false;
        writes.oGLP_Principal_Abrir = true;
        writes.AUX_A_SV_02 = true;
        log('PRINCIPAL: Abrindo SV-02...');
        state.step = 1; state.timer = 0;
    }
    else if (state.step === 1) {
        state.timer++;
        if (plc.iSV_02_Opened === true || state.timer >= 8) {
            if (!plc.iSV_02_Opened) log('AVISO: Timeout iSV_02_Opened');
            else log('PRINCIPAL: SV-02 ABERTA - FIT-02: ' + (plc.iFIT_02_Ar_PV||0).toFixed(1) + ' Nm³/h');
            writes.Inicia_Queima = true;
            state.estado = 'QUEIMA_PLENA'; state.step = 0; state.timer = 0;
        }
    }
    break;

  case 'QUEIMA_PLENA':
    state.timer++;
    // Verifica alarme de temperatura caixa de vento
    if (plc.iTIT_03_Cx_Vento_PV > (plc.Temp_CxVento_Max || 900)) {
        log('ALARME: TIT-03 Cx Vento excedida: ' + (plc.iTIT_03_Cx_Vento_PV||0).toFixed(0) + '°C > ' + (plc.Temp_CxVento_Max||900));
        writes.EMERGENCIA_ALARME1 = true;
    }
    // Verifica perda de chama principal
    if (plc.iZS_Queimador_Principal === false && state.timer > 5) {
        log('FALHA: Chama principal perdida!');
        writes.EMERGENCIA_ALARME1 = true;
        state.estado = 'FALHA'; break;
    }
    if (state.timer % 10 === 0) {
        log('QUEIMA PLENA: TIT-01=' + (plc.iTIT_01_Refratario_PV||0).toFixed(0) +
            '°C | CxVento=' + (plc.iTIT_03_Cx_Vento_PV||0).toFixed(0) +
            '°C | FIT-01=' + (plc.iFIT_01_GLP_PV||0).toFixed(1) +
            ' | Tempo=' + state.timer + 's');
    }
    // Fim por comando ou tempo mínimo de sinterização
    var tSint = plc.Min_TempoSinterizacao || 120;
    if (plc.Final_Queima === true || state.timer >= tSint) {
        log('QUEIMA: Finalizando - tempo=' + state.timer + 's');
        writes.Selo_TempoSinterizacao = true;
        state.estado = 'DESLIGAMENTO'; state.step = 0; state.timer = 0;
    }
    break;

  case 'DESLIGAMENTO':
    if (state.step === 0) {
        writes.oSV_02_Abrir = false; writes.oSV_02_Fechar = true;
        writes.oGLP_Principal_Abrir = false;
        writes.AUX_F_SV_02 = true; writes.AUX_A_SV_02 = false;
        log('DESLIGAMENTO: Fechando SV-02 (principal)...');
        state.step = 1; state.timer = 0;
    }
    else if (state.step === 1) {
        state.timer++;
        if (plc.iSV_02_Closed === true || state.timer >= 6) {
            log('DESLIGAMENTO: SV-02 fechada - fechando piloto...');
            writes.oSV_01_Abrir = false; writes.oSV_01_Fechar = true;
            writes.oGLP_Piloto_Abrir = false;
            state.step = 2; state.timer = 0;
        }
    }
    else if (state.step === 2) {
        state.timer++;
        if (plc.iSV_01_Closed === true || state.timer >= 6) {
            log('DESLIGAMENTO: Piloto fechado - fechando GLP geral...');
            writes.oGLP_Fechada = true;
            state.step = 3; state.timer = 0;
        }
    }
    else if (state.step === 3) {
        state.timer++;
        if (plc.iSV_GLP_Closed === true || state.timer >= 6) {
            log('DESLIGAMENTO: GLP geral fechado - iniciando resfriamento...');
            state.estado = 'RESFRIAMENTO'; state.step = 0; state.timer = 0;
        }
    }
    break;

  case 'RESFRIAMENTO':
    state.timer++;
    var tResf = plc.Min_TempoResfriamento || 60;
    if (state.timer % 10 === 0) {
        log('RESFRIAMENTO: ' + state.timer + 's/' + tResf + 's | TIT-01=' + (plc.iTIT_01_Refratario_PV||0).toFixed(0) + '°C');
    }
    if (state.timer >= tResf) {
        writes.oAciona_Soprador = false;
        writes.oCx_Vento_Out = false;
        writes.Inicia_Queima = false;
        writes.Final_Queima = false;
        writes.Inicio_HMI = false;
        writes.Teste_IHM = false;
        log('RESFRIAMENTO: Concluído - Sistema em IDLE');
        state.estado = 'IDLE'; state.step = 0; state.timer = 0;
    }
    break;

  case 'FALHA':
    if (plc.Reset_IHM === true || plc.Reset_Seq === true) {
        // Reset completo
        writes.EMERGENCIA_ALARME1 = false;
        writes.oSV_01_Abrir = false; writes.oSV_01_Fechar = true;
        writes.oSV_02_Abrir = false; writes.oSV_02_Fechar = true;
        writes.oGLP_Piloto_Abrir = false; writes.oGLP_Principal_Abrir = false;
        writes.oAciona_Ignicao = false; writes.oAciona_Soprador = false;
        writes.Inicio_HMI = false; writes.Inicia_Queima = false;
        writes.Reset_IHM = false; writes.Reset_Seq = false;
        log('RESET: Falha reconhecida - retornando ao IDLE');
        state.estado = 'IDLE'; state.step = 0; state.timer = 0;
    }
    break;
}

flow.set('seq_state', state);

// Saída 1: escrita no CLP | Saída 2: update dashboard
var write_msgs = Object.keys(writes).map(function(tag){
    return {topic: tag, tag: tag, payload: writes[tag]};
});

return [write_msgs.length ? write_msgs : null,
        {payload: {plc: plc, state: state}}];

var cmd = msg.payload;
var writes = [];
switch(cmd) {
  case 'iniciar':
    writes.push({topic:'Inicio_HMI',  tag:'Inicio_HMI',  payload:true});
    node.status({fill:'green',shape:'dot',text:'Inicio_HMI → TRUE'});
    break;
  case 'finalizar':
    writes.push({topic:'Final_Queima',tag:'Final_Queima',payload:true});
    node.status({fill:'orange',shape:'dot',text:'Final_Queima → TRUE'});
    break;
  case 'reset':
    writes.push({topic:'Reset_IHM', tag:'Reset_IHM', payload:true});
    writes.push({topic:'Reset_Seq', tag:'Reset_Seq', payload:true});
    node.status({fill:'blue',shape:'dot',text:'Reset enviado'});
    break;
  case 'emergencia':
    writes.push({topic:'EMERGENCIA_ALARME1',tag:'EMERGENCIA_ALARME1',payload:true});
    writes.push({topic:'iZS_Emerg',         tag:'iZS_Emerg',         payload:true});
    node.status({fill:'red',shape:'dot',text:'EMERGÊNCIA!'});
    break;
  case 'teste':
    writes.push({topic:'Teste_IHM',tag:'Teste_IHM',payload:true});
    node.status({fill:'purple',shape:'dot',text:'Forçando principal'});
    break;
}
return [writes];

// Recebe eventos de status do eth-ip
var estado = msg.payload;
node.status({fill: estado ? 'green':'red', shape:'dot',
             text: estado ? 'Conectado 192.168.250.10':'Desconectado'});
return null;
